5	function formatCents(cents) {
6	  const sign = cents < 0 ? '-' : '';
7	  const abs = Math.abs(cents);
8	  const dollars = Math.floor(abs / 100);
9	  const rem = String(abs % 100).padStart(2, '0');
10	  return `${sign}$${dollars}.${rem}`;
