const EXCLUDED_STATUSES = new Set(['cancelled', 'refunded']);

function revenueByMonth(orders) {
  const totals = new Map();

  for (const order of orders) {
    if (EXCLUDED_STATUSES.has(order.status)) continue;

    const d = new Date(order.placedAt);
    const year = d.getUTCFullYear();
    const month = String(d.getUTCMonth() + 1).padStart(2, '0');
    const key = `${year}-${month}`;

    totals.set(key, (totals.get(key) ?? 0) + order.amountCents);
  }

  return Array.from(totals.entries())
    .sort(([a], [b]) => (a < b ? -1 : 1))
    .map(([month, cents]) => ({ month, cents }));
}

